  ('aboriginal-6f0ba476-moex-00071', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '國際運輸事業自中華民國境內載運客、貨出境者，其營業稅銷售額之計算，下列何者正確？', '["海運事業，自中華民國境內載運客、貨至境外第一站之票價或運費", "海運事業，自中華民國境內載運客、貨至境外之全部票價或運費", "空運事業，自中華民國境內載運客、貨至境外第一站之票價或運費", "空運事業，自中華民國境內載運客、貨至境外之全部票價或運費"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "ebc056a8d8b9", "answer_pdf_sha1": "eec9f9a30014", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00072', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，納稅義務人核定應使用統一發票而不使用，除通知限期改正 或補辦外，並得處罰鍰；屆期仍未改正或補辦者，得按次處罰，並得停止其營業。請問該法所定 之罰鍰額度為：', '["新臺幣2千元以上2萬元以下", "新臺幣3千元以上3萬元以下", "新臺幣5千元以上5萬元以下", "新臺幣6千元以上6萬元以下"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "ebc056a8d8b9", "answer_pdf_sha1": "eec9f9a30014", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00073', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '關於貨物稅之規定，下列敘述何者錯誤？', '["應稅貨物之完稅價格應包括該貨物之包裝從物價格", "腳踏車裝有輔助原動機者，從價徵收貨物稅17%", "納稅義務人短報出廠數量者，除補徵稅款外，按補徵稅額處四倍以下罰鍰", "已納貨物稅之貨物，滯銷退廠整理者，退還原納貨物稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "ebc056a8d8b9", "answer_pdf_sha1": "eec9f9a30014", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00074', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '關於特種貨物及勞務稅條例，下列敘述何者錯誤？', '["包括駕駛人座位在內，座位在九座以下之載人汽車，且每輛銷售價格或完稅價格達新臺幣 300 萬元者，為特種貨物", "銷售價格新臺幣40萬元之入會權利，另收取20萬元之保證金，於退會時退還，兩項金額合併 計算，為特種勞務", "進口特種貨物之完稅價格，包括應稅的關稅稅額及營業稅稅額", "納稅義務人銷售或產製特種貨物或特種勞務，其銷售價格指銷售時收取之全部代價，包括在價 額外收取之一切費用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "ebc056a8d8b9", "answer_pdf_sha1": "eec9f9a30014", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
